import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"流水岩碎拳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/流水岩碎拳.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/流水岩碎拳.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/流水岩碎拳.md"};function o(d,p,_,l,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"流水岩碎拳",tabindex:"-1"},[t("流水岩碎拳 "),r("a",{class:"header-anchor",href:"#流水岩碎拳","aria-label":'Permalink to "流水岩碎拳"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="流水岩碎拳-1" tabindex="-1">流水岩碎拳 <a class="header-anchor" href="#流水岩碎拳-1" aria-label="Permalink to &quot;流水岩碎拳&quot;">​</a></h1><p>流水岩碎拳</p><p>邦古用自己的方式，让与邦普一同学习的拳法进化，重新创造这门必杀拳。能够流畅的挡掉敌人的攻击，再针对空隙一击致胜——这便是流水岩碎拳的奥义，全身上下的伤痕与壮阔的拳法，在阐述他曾历经过多刻苦的修行与多可怕的战场。<br> 流水岩碎拳是通过如同流水一般的拳法打击敌人，击碎岩石的防御型招式，是将攻来的所有攻势以诡异的拳路与力道，将其弹开，即使原本是正面击中便会重伤甚至致死的攻击，也能将其挡开。</p><p>流派武器：本流派的徒手攻击由破坏敌人平衡的推手及进肘、铁山靠、掌击，拳，扫腿等肉搏武器组成。本流派不兼容武器。</p><p>流水呼吸法<br> 价格：D+500<br> 购买前提：武技3+<br> 前置秘法：无<br> 效果：你获得名为“流水劲”的能量池，关键属性为力量+感知，类似于通用能量所拥有的”气“，但与其相比更加的悠长而规律，因此，仅可以其驱动以偏斜防御或者步法为主的，由气推动的技艺，流水的本意便是犹如同水的流动一般控制力量的流动。<br> 流水劲的恢复方式等同与气的恢复方式。</p><p>消力：结合在一次格挡或全防御动作中，武者操纵力量的流动偏斜攻击，从而保护自身。<br> 在进行一次格挡或全防御时，额外消耗2点”流水劲“，武者本轮获得4点偏斜防御。</p><p>瞬身功<br> 价格：C+1000<br> 购买前提：武技3+<br> 消耗：6点流水劲<br> 动作：反射动作<br> 前置秘法：流水呼吸法</p><p>空山无人，水流花开，以特殊的步伐，武者在攻击命中前宛若流水一般躲避，无人能斩断流水，亦无人能触碰武者。</p><p>效果：在非武者回合，武者在面对他人一次攻击时使用，在攻击落到武者身上的瞬间，武者可以【打断性】的顺应攻击传导的力道移动，最多移动15米并获得6点闪避防御。因为是顺应攻击传导的力量移动，因此武者无法主动选择移动的方向，其移动的方向总是与受到攻击方向相反。<br> 武者每轮只能使用一次瞬身功<br> 武学推演：D+1000<br> 瞬身功可以自由动作使用</p><p>徒身肩振<br> 价格：C+1000<br> 购买前提：武技3+<br> 消耗：3点流水劲<br> 动作：自由动作<br> 前置秘法：流水呼吸法</p><p>武者掌控目标的力量流动，将攻击在间不容发的空挡破坏，并用肩膀目标冲撞开的技巧，徒身肩振是仅仅针对近战攻击的应对技巧。</p><p>效果：武者可通过引导对方力量的流动，只需用微小的力量便可将目标撞开。<br> 每轮一次，武者在面对一次近战攻击时，若发起者在攻击武者时自己也恰巧处于武者的触及范围内，武者可以自由动作对其打断性的进行一次冲撞，获得2dp增强加值并具有C级先制，对方正常对抗。武者可以选择本次冲撞的方向，但因为是引导对方的力量流动，所以你不能选择将目标朝着他攻击过来的路径撞回去，而是引导他的力量想着其他方向转移。</p><p>识破<br> 价格：C+1000<br> 购买前提：武技3+<br> 消耗：2点流水劲<br> 前置秘法：流水呼吸法，流水极意</p><p>锻炼动态视力，事先预判敌人的动作，在对方的动作展开之前便以展开迎击，这是无论何种刁钻的攻击都可以如常应对的能力</p><p>效果：只要武者未处于失明状态，则武者便能免疫B级措手不及同时，当武者处于肉搏格挡状态时，可以消耗2点流水劲提高自己的动态视力，此时，人物立即进行一次感知属性的检定，并获得等同于成功数的洞察防御，该洞察防御持续一轮。</p><p>武学推演：B+2000<br> 武者总是可以观察到目标的攻击的弱点，并在攻击中如水一般流淌闪避。<br> 识破带来的免疫措手不及效果提升至A级。<br> 人物在于肉搏格挡状态时，若使用识破，可以则最小的动作,精准的格挡拨开来袭的威胁，每轮一次，受到攻击时可无需动作即可如同进行招架一般抵消对方的成功数。</p><p>牙插指<br> 价格：C+1000<br> 购买前提：武技5+<br> 消耗：3点流水劲<br> 前置秘法：流水呼吸法</p><p>万物皆有弱点，而水无孔不入，武者准确无比地命中极小的要害，动作就像流水般毫不停滞。</p><p>效果：若一次攻击是单体近战肉搏攻击，则可以附加本招式。<br> 被攻击的目标需要立即进行一次敏捷+武技(任意肉搏专业)，来对抗你的肉搏攻击鉴定，若对抗失败。<br> 则你的本次攻击视为具有【法破】特性，且对视为对对抗失败的目标带有C级措手不及和【毁灭】。</p><p>狂澜流<br> 价格：A+4000<br> 购买前提：武技8+<br> 消耗：14点流水劲<br> 动作：标准动作<br> 前置秘法：流水呼吸法,牙插指</p><p>运起流水气劲，将敌方卷入迅捷的乱波狂澜之中，为了确实置打到对手，毫不留情地打出无数发如同水银泄地的猛攻，如水滴石穿一般终结对手。</p><p>效果：武者对目标进行一次攻击，若命中且造成伤害，则立即消耗自由动作重复攻击，第二次攻击的的攻击骰为第一次次攻击的成功数，若第二次依然命中且造成伤害，则自由动作以第二次攻击的成功数作为第三次攻击的攻击骰.......直到无法命中或者无法造成伤害为止。<br> 狂澜流是犹如流水一般无孔不入的攻击，流水劲破体而入，被攻击的目标只觉得挡无可挡，避无可避，攻击视为【接触攻击】并具有【8加骰】。当狂澜流的第一次攻击命中后，受击方使用格挡与全防御带来的加值无法对狂澜流剩余的攻击生效，这是A级幻象来源的胁迫效果。</p><p>流水极意<br> 价格：B+2000<br> 购买前提：武技8+<br> 动作：迅捷动作<br> 持续时间：一轮<br> 前置秘法：流水呼吸法，</p><p>柔似流水，刚可碎岩石，无论多么湍急的河流，最终都会归于汪洋大海之中。</p><p>效果：武者维持流水极意架势的前提下，只要是武者可以意识到的攻击（即不处于措手不及），武者对这些攻击便视为一直处于肉搏格挡状态，武者获得基于格挡防御的【坚韧】与【适应】。</p><p>流水阵<br> 价格：A+4000<br> 购买前提：武技11+<br> 动作：特殊<br> 持续：一轮<br> 前置秘法：流水呼吸法 ，流水极意，徒身肩振或瞬身功（武学推演）其一</p><p>拳时如闪电，劲慢如柔水，行意不拘形 ，流水之力，亦能惊涛拍浪！。</p><p>流水岩碎拳的奥义之一，武艺将自身化为流水，如水般流畅的化解敌人的攻击，甚至能操控攻击的流动，将攻击返还转移，此名为“流水阵”。</p><p>效果：人物在习得流水阵后，开启流水极意时会同时自动的开启流水阵，处于流水阵状态下，对武者可以意识到的攻击，武者对这些攻击便视为进行了全力防御，这与流水极意状态获得的好处叠加。</p><p>每轮一次，在开启流水阵后，若武者被一名可被定位的目标攻击，且对方的该次攻击没有造成任何伤害（包括使用徒身肩振或瞬身功打断对方攻击），则武者可以立刻以一个自由动作，以对方的这次攻击检定和剩余射程，对攻击者或者场景内武者能够定位、且处于（攻击剩余的）射程内的任何一人进行一次攻击，在判定上，这次攻击仍然是由攻击方而非武者所发起。这是一个S级、创伤来源的胁迫效果。</p><p>开启流水阵状态时，选择并获得以下效果其一：<br> 1.武者徒身肩振时可额外将目标击退力量*5米，持续一轮。<br> 2.武者瞬身功可额外移动敏捷*5米，持续一轮。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',33)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
